sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {

    if (isLoading || !newValue)
        return;

    var student = g_form.getValue('student');
    var drive = g_form.getValue('drive');

    if (!student || !drive)
        return;

    var ga = new GlideAjax('PlacementUtils');

    ga.addParam('sysparm_name', 'checkEligibility');
    ga.addParam('sysparm_student', student);
    ga.addParam('sysparm_drive', drive);

    ga.getXMLAnswer(function(answer) {

        g_form.hideFieldMsg('drive', true);

        if (answer == 'Eligible') {

            g_form.showFieldMsg(
                'drive',
                'Eligible for this drive',
                'info'
            );

        } else {

            g_form.showFieldMsg(
                'drive',
                'May not meet eligibility criteria',
                'error'
            );

        }

    });

}
